async function main() {
  let count = 0;
  for (const item of updates) {
    try {
      await prisma.product.update({
        where: { slug: item.slug },
        data: { description: item.description, metaDescription: item.metaDescription }
      });
      count++;
      const wc = item.description.split(/\s+/).length;
      const mc = item.metaDescription.length;
      console.log(`OK: ${item.slug} (${wc} words, ${mc} chars meta)`);
    } catch(e) {
      console.log('SKIP:', item.slug, e.message.substring(0, 80));
    }
  }
  console.log("Updated:", count);
}
main().then(() => prisma.$disconnect());
